import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GeneratedData {
  run: string;
  serial: string;
  mrz: string;
  url: string;
}

export enum DocType {
  CEDULA = 'CEDULA'
}

/**
 * Calculates the RUT/RUN check digit (DV)
 */
export function calculateDV(rut: number): string {
  let m = 0, s = 1;
  for (; rut; rut = Math.floor(rut / 10)) {
    s = (s + (rut % 10) * (9 - (m++ % 6))) % 11;
  }
  return s ? (s - 1).toString() : 'K';
}

/**
 * Generates a random RUN (10MM to 25MM)
 */
export function generateRandomRUN(): string {
  const num = Math.floor(Math.random() * (25000000 - 10000000) + 10000000);
  const dv = calculateDV(num);
  return `${num}-${dv}`;
}

/**
 * Generates a random Serial (9 digits)
 */
export function generateRandomSerial(): string {
  return Math.floor(Math.random() * 900000000 + 100000000).toString();
}

/**
 * Generates a random MRZ numeric string (20 digits)
 */
export function generateRandomMRZ(): string {
  let res = '';
  for(let i = 0; i < 20; i++) {
    res += Math.floor(Math.random() * 10).toString();
  }
  return res;
}

export function buildUrl(run: string, serial: string, mrz: string): string {
  return `https://portal.nuevosidiv.registrocivil.cl/document-validity?RUN=${run}&type=CEDULA&serial=${serial}&mrz=${mrz}`;
}

import React from 'react';

interface QRCodeProps {
  value: string;
  size?: number;
}

const QRCode: React.FC<QRCodeProps> = ({ value, size = 250 }) => {
  const encodedValue = encodeURIComponent(value);
  const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=${size}x${size}&data=${encodedValue}`;

  return (
    <div className="flex flex-col items-center justify-center p-4 bg-white rounded-xl shadow-inner border border-slate-100">
      <img 
        src={qrUrl} 
        alt="QR Code" 
        className="w-full h-auto max-w-[250px] aspect-square object-contain"
      />
    </div>
  );
};

export default QRCode;

